import api from './api';

export interface DashboardStats {
  users: {
    total: number;
    active: number;
    new_today: number;
    new_this_week: number;
    growth_percentage: number;
  };
  subscriptions: {
    total_active: number;
    revenue_this_month: number;
    revenue_total?: number;
    revenue_growth: number;
    churn_rate?: number;
  };
  usage: {
    total_sessions: number;
    total_messages: number;
    total_chats?: number;
    total_images?: number;
    total_words?: number;
    sessions_today?: number;
    active_sessions_today?: number;
  };
  models: {
    total: number;
    active: number;
    most_used: string;
  };
}

export interface UsageData {
  date: string;
  sessions: number;
  messages: number;
  chats?: number;
  images?: number;
  words?: number;
}

export interface RevenueData {
  date: string;
  amount: number;
  subscriptions?: number;
}

export interface UserGrowthData {
  date: string;
  total_users: number;
  new_users: number;
}

export const analyticsService = {
  async getDashboardStats(): Promise<DashboardStats> {
    const response = await api.get<DashboardStats>('/accounts/analytics/dashboard/');
    // Normalize response to handle both old and new field names
    const data = response.data;
    return {
      ...data,
      usage: {
        ...data.usage,
        total_chats: data.usage.total_sessions || data.usage.total_chats || 0,
        total_images: data.usage.total_images || 0,
        total_words: data.usage.total_words || 0,
        total_sessions: data.usage.total_sessions || 0,
        total_messages: data.usage.total_messages || 0,
      }
