  visible,
  actionName,
  cost,
  currentCredits,
  onConfirm,
  onCancel,
  isLoading = false,
}) => {
  const hasEnoughCredits = currentCredits >= cost;
  const remainingCredits = currentCredits - cost;

  return (
    <Modal
      visible={visible}
      animationType="fade"
      transparent={true}
      onRequestClose={onCancel}
    >
      <View style={styles.overlay}>
        <View style={styles.container}>
