import React, { useState } from 'react';
import { 
  View, 
  Text, 
  TouchableOpacity, 
  StyleSheet, 
  Modal,
  FlatList,
  Pressable,
} from 'react-native';
import { Ionicons } from '@expo/vector-icons';
import { colors, spacing, borderRadius } from '../theme';
import { getCleanModelName } from '../utils/modelUtils';

interface Model {
  id: number;
  name: string;
  description?: string;
  [key: string]: any;
}

interface ModelSelectorProps {
  selected: number | string | { id: number } | null;
  onSelect: (model: Model) => void;
  models?: Model[];
}

const ModelSelector: React.FC<ModelSelectorProps> = ({ selected, onSelect, models = [] }) => {
  const [isOpen, setIsOpen] = useState(false);

  const selectedId = selected && typeof selected === 'object' ? selected.id : selected;
  const selectedModel = models.find(m => m.id === selectedId);
  const displayName = selectedModel ? getCleanModelName(selectedModel.name) : 'Select Model';

  const handleSelect = (model: Model) => {
    onSelect(model);
    setIsOpen(false);
  };

  return (
    <>
      <TouchableOpacity 
        style={styles.selector} 
        onPress={() => setIsOpen(true)}
        activeOpacity={0.7}
      >
        <Text style={styles.selectorText} numberOfLines={1}>
          {displayName}
        </Text>
        <Ionicons 
          name="chevron-down" 
          size={18} 
          color={colors.textSecondary} 
        />
      </TouchableOpacity>

      <Modal
        visible={isOpen}
        transparent
        animationType="fade"
