import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import AsyncStorage from '@react-native-async-storage/async-storage';
import { authService, User, LoginCredentials, RegisterData, STORAGE_KEYS } from '../services';

interface AuthContextType {
  user: User | null;
  isLoading: boolean;
  isAuthenticated: boolean;
  login: (credentials: LoginCredentials) => Promise<void>;
  register: (data: RegisterData) => Promise<{ message: string }>;
  activateAccount: (email: string, code: string) => Promise<{ message: string }>;
  googleLogin: (accessToken: string) => Promise<void>;
  logout: () => Promise<void>;
  refreshUser: () => Promise<void>;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export function AuthProvider({ children }: { children: ReactNode }) {
  const [user, setUser] = useState<User | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    let isMounted = true;

    const checkAuth = async () => {
      try {
        const token = await AsyncStorage.getItem(STORAGE_KEYS.ACCESS_TOKEN);
        if (token && isMounted) {
          const profile = await authService.getProfile();
          if (isMounted) setUser(profile);
        }
      } catch (error) {
        // Token is invalid or expired
        if (isMounted) {
          await AsyncStorage.multiRemove([
            STORAGE_KEYS.ACCESS_TOKEN,
            STORAGE_KEYS.REFRESH_TOKEN,
            STORAGE_KEYS.USER,
          ]);
        }
      } finally {
        if (isMounted) setIsLoading(false);
      }
    };

    checkAuth();
    return () => {
      isMounted = false;
    };
  }, []);

  const login = async (credentials: LoginCredentials) => {
    const response = await authService.login(credentials);
    setUser(response.user);
  };

  const register = async (data: RegisterData): Promise<{ message: string }> => {
    // Registration now returns a message (requires OTP verification)
    const response = await authService.register(data);
    return response;
  };

  const activateAccount = async (email: string, code: string): Promise<{ message: string }> => {
    const response = await authService.activateAccount(email, code);
    return response;
  };

  const googleLogin = async (accessToken: string) => {
    const response = await authService.googleLogin(accessToken);
    setUser(response.user);
  };

  const logout = async () => {
    await authService.logout();
    setUser(null);
  };

  const refreshUser = async () => {
    try {
      const profile = await authService.getProfile();
      setUser(profile);
    } catch (error) {
      // If refresh fails, log out
      await logout();
    }
  };

  return (
    <AuthContext.Provider
      value={{
        user,
        isLoading,
        isAuthenticated: !!user,
        login,
        register,
        activateAccount,
        googleLogin,
        logout,
        refreshUser,
      }}
    >
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
}

export default AuthContext;

import React, { createContext, useContext, useState, useCallback, useEffect, ReactNode, useRef } from 'react';
import { AppState, AppStateStatus } from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import { creditsService, STORAGE_KEYS } from '../services';
import { useAuth } from './AuthContext';

export interface CreditAccount {
  credits: number;
  bonus_credits?: number;
  total_credits?: number;
  usedWords?: number;
  isPro?: boolean;
}

interface CreditsContextType {
  credits: CreditAccount | null;
  isLoading: boolean;
  isRefreshing: boolean;
  fetchCredits: () => Promise<void>;
  refreshCredits: () => Promise<void>;
  deductCredits: (amount: number, description: string) => Promise<boolean>;
  addCredits: (amount: number, description: string) => Promise<void>;
  hasEnoughCredits: (amount: number) => boolean;
}

const CreditsContext = createContext<CreditsContextType | undefined>(undefined);

export function CreditsProvider({ children }: { children: ReactNode }) {
  const { isAuthenticated } = useAuth();
  const [credits, setCredits] = useState<CreditAccount | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isRefreshing, setIsRefreshing] = useState(false);
  const appState = useRef(AppState.currentState);

  const fetchCredits = useCallback(async () => {
    try {
      const token = await AsyncStorage.getItem(STORAGE_KEYS.ACCESS_TOKEN);
      if (!token) {
        setCredits(null);
        setIsLoading(false);
        return;
      }

      setIsLoading(true);
      const data = await creditsService.getCreditBalance();
      setCredits(data);
    } catch (error) {
      console.error('Error fetching credits:', error);
      setCredits(null);
    } finally {
      setIsLoading(false);
    }
  }, []);

  const refreshCredits = useCallback(async () => {
    try {
      const token = await AsyncStorage.getItem(STORAGE_KEYS.ACCESS_TOKEN);
      if (!token) {
        return;
      }

      setIsRefreshing(true);
      const data = await creditsService.getCreditBalance();
      setCredits(data);
    } catch (error) {
      console.error('Error refreshing credits:', error);
    } finally {
      setIsRefreshing(false);
    }
  }, []);

  // Initial load
  useEffect(() => {
    fetchCredits();
  }, [fetchCredits]);

  // Keep credits synced with login/logout state changes.
  useEffect(() => {
    if (isAuthenticated) {
      refreshCredits();
    } else {
      setCredits(null);
      setIsLoading(false);
    }
  }, [isAuthenticated, refreshCredits]);

  // Refresh credits when app returns to foreground.
  useEffect(() => {
    const subscription = AppState.addEventListener('change', (nextAppState: AppStateStatus) => {
      if (appState.current.match(/inactive|background/) && nextAppState === 'active') {
        refreshCredits();
      }
      appState.current = nextAppState;
    });

    return () => {
      subscription.remove();
    };
  }, [refreshCredits]);

  const hasEnoughCredits = useCallback(
    (amount: number): boolean => {
      if (!credits) return false;
      return credits.credits >= amount;
    },
    [credits]
  );

  const deductCredits = useCallback(
    async (amount: number, description: string): Promise<boolean> => {
      if (!hasEnoughCredits(amount)) {
        return false;
      }

      try {
        setCredits((prev) => {
          if (!prev) return prev;
          return {
            ...prev,
            credits: Math.max(0, prev.credits - amount),
            total_credits: Math.max(0, (prev.total_credits || prev.credits) - amount),
          };
        });

        await refreshCredits();
        return true;
      } catch (error) {
        console.error('Error deducting credits:', error);
        await fetchCredits();
        return false;
      }
    },
    [hasEnoughCredits, refreshCredits, fetchCredits]
  );

  const addCredits = useCallback(async (amount: number, description: string) => {
    try {
      setCredits((prev) => {
        if (!prev) return prev;
        return {
          ...prev,
          credits: prev.credits + amount,
          total_credits: (prev.total_credits || prev.credits) + amount,
        };
      });

      await refreshCredits();
    } catch (error) {
      console.error('Error adding credits:', error);
      await fetchCredits();
    }
  }, [refreshCredits, fetchCredits]);

  return (
    <CreditsContext.Provider
      value={{
        credits,
        isLoading,
        isRefreshing,
        fetchCredits,
        refreshCredits,
        deductCredits,
        addCredits,
        hasEnoughCredits,
      }}
    >
      {children}
    </CreditsContext.Provider>
  );
}

export function useCredits() {
  const context = useContext(CreditsContext);
  if (context === undefined) {
    throw new Error('useCredits must be used within a CreditsProvider');
  }
  return context;
}

