interface Message {
  id: string;
  content: string;
  isUser: boolean;
  timestamp: string;
  attachments?: AttachmentItem[];
}

type AttachmentType = 'image' | 'document';

interface AttachmentItem {
  id: string;
  uri: string;
  name: string;
  type: AttachmentType;
  mimeType?: string;
  size?: number;
  base64?: string; // pre-encoded at pick time for reliable sending
}

interface PendingMessagePayload {
  text: string;
  images: string[];
  dedupeKey: string;
}

interface ChatScreenProps {
  navigation?: any;
  sessionId?: number;
}

