  // Storage key for persisting chat state
  const CHAT_STORAGE_KEY = 'z99_chat_state';
  const API_ORIGIN = API_BASE_URL.replace(/\/api\/v1$/, '');

  const toAbsoluteMediaUri = useCallback((uri: string): string => {
    if (!uri) return uri;
