    } catch (error) {
      console.error('Failed to save chat state:', error);
    }
  }, [messages, session, selectedModel]);

  // Load chat state from AsyncStorage
  const loadChatState = useCallback(async () => {
    try {
      const savedState = await AsyncStorage.getItem(CHAT_STORAGE_KEY);
      if (savedState) {
        const chatState = JSON.parse(savedState);
        restoredSessionIdRef.current = chatState.sessionId || null;
        restoredModelIdRef.current = chatState.modelId || null;

        // Restore messages - no time limit, persist until cleared
        if (chatState.messages && chatState.messages.length > 0) {
          setMessages(chatState.messages);
          console.log('Restored', chatState.messages.length, 'messages from storage');
        }

        // Restore persisted session so conversation remains linked across app restarts.
        if (chatState.sessionId) {
          try {
            const sessionData = await chatService.getSession(chatState.sessionId);
            setSession(sessionData);
          } catch (sessionError) {
            console.warn('Failed to restore persisted session:', sessionError);
          }
        }

        return true;
      }
      return false;
    } catch (error) {
      console.error('Failed to load chat state:', error);
      return false;
    }
  }, []);

  // Handle file/image attachment
  const handleAttachFile = async () => {
    try {
      // Request permission
      const { status } = await ImagePicker.requestMediaLibraryPermissionsAsync();
      if (status !== 'granted') {
        Alert.alert(
          t('common.error'),
          t('chat.permissionDenied') || 'Permission to access media library is required'
        );
        return;
      }

      // Show options
      Alert.alert(
        t('chat.attachFile') || 'Attach File',
        t('chat.chooseSource') || 'Choose source',
        [
          {
            text: t('chat.takePhoto') || 'Take Photo',
            onPress: async () => {
              const result = await ImagePicker.launchCameraAsync({
                mediaTypes: ImagePicker.MediaTypeOptions.Images,
                allowsEditing: true,
                quality: 0.1,
                base64: true, // capture base64 directly — reliable across all platforms
              });
              if (!result.canceled && result.assets[0]) {
                const asset = result.assets[0];
                const mimeType = asset.mimeType || 'image/jpeg';
                addAttachment({
                  id: `attach-${Date.now()}`,
                  uri: asset.uri,
                  name: asset.fileName || `photo-${Date.now()}.jpg`,
                  type: 'image',
                  mimeType,
                  size: asset.fileSize,
                  base64: asset.base64 ? `data:${mimeType};base64,${asset.base64}` : undefined,
                });
                showToast(t('chat.imageAttached') || 'Image attached', 'success');
              }
            },
          },
          {
            text: t('chat.chooseFromGallery') || 'Choose from Gallery',
            onPress: async () => {
              const result = await ImagePicker.launchImageLibraryAsync({
                mediaTypes: ImagePicker.MediaTypeOptions.Images,
                allowsEditing: true,
                quality: 0.1,
                base64: true, // capture base64 directly — reliable across all platforms
              });
              if (!result.canceled && result.assets[0]) {
                const asset = result.assets[0];
                const mimeType = asset.mimeType || 'image/jpeg';
                addAttachment({
                  id: `attach-${Date.now()}`,
                  uri: asset.uri,
                  name: asset.fileName || `image-${Date.now()}.jpg`,
                  type: 'image',
                  mimeType,
                  size: asset.fileSize,
                  base64: asset.base64 ? `data:${mimeType};base64,${asset.base64}` : undefined,
                });
                showToast(t('chat.imageAttached') || 'Image attached', 'success');
              }
            },
          },
          {
            text: t('chat.chooseDocument') || 'Choose Document',
            onPress: async () => {
              const result = await DocumentPicker.getDocumentAsync({
                type: '*/*',
                copyToCacheDirectory: true,
                multiple: false,
              });

              if (!result.canceled && result.assets[0]) {
                const asset = result.assets[0];
                addAttachment({
                  id: `attach-${Date.now()}`,
                  uri: asset.uri,
                  name: asset.name || `document-${Date.now()}`,
                  type: 'document',
                  mimeType: asset.mimeType || 'application/octet-stream',
                  size: asset.size,
                });
                showToast(t('chat.fileAttached') || 'File attached', 'success');
              }
            },
          },
          {
            text: t('common.cancel'),
            style: 'cancel',
          },
        ]
      );
