      console.error('Error picking image:', error);
      Alert.alert(t('common.error'), t('chat.errorAttachFile') || 'Failed to attach file');
    }
  };

  const removeAttachment = (id: string) => {
    setAttachedFiles((prev) => prev.filter((item) => item.id !== id));
  };

  // Removed buildDocumentContext - documents are now included via buildExtractedDocumentContext

  const isTextDocument = (file: AttachmentItem) => {
    const lowerName = file.name.toLowerCase();
    const mime = (file.mimeType || '').toLowerCase();

    if (mime.startsWith('text/')) return true;
    if (mime.includes('json') || mime.includes('csv') || mime.includes('xml')) return true;

    return /\.(txt|md|csv|json|xml|html|log|py|js|ts|tsx|jsx|java|sql|yml|yaml)$/i.test(lowerName);
  };

  const buildDefaultAttachmentPrompt = (messageText: string, attachments: AttachmentItem[]) => {
    if (messageText.trim().length > 0) {
      return messageText;
    }

    const hasImages = attachments.some((item) => item.type === 'image');
    const hasDocs = attachments.some((item) => item.type === 'document');

    if (hasImages && hasDocs) {
      return 'Please analyze the attached images and documents, then provide a concise summary and key points.';
    }

    if (hasImages) {
      return 'Please analyze the attached image and describe key details, objects, and context.';
    }

    if (hasDocs) {
      return 'Please analyze the attached documents and provide a concise summary with key findings.';
    }

    return messageText;
  };

  // Returns { context, unreadable } — unreadable docs must be shown to user BEFORE sending
  const buildExtractedDocumentContext = async (attachments: AttachmentItem[]): Promise<{ context: string; unreadableNames: string[] }> => {
    const docs = attachments.filter((item) => item.type === 'document');
    if (docs.length === 0) return { context: '', unreadableNames: [] };

    const maxDocsToInclude = 5;
    const maxCharsPerDoc = 8000;
    const parsedSections: string[] = [];
    const unreadableNames: string[] = [];

    for (const doc of docs.slice(0, maxDocsToInclude)) {
      // First try: plain text files can be read directly on device
      if (isTextDocument(doc)) {
        try {
          const raw = await FileSystem.readAsStringAsync(doc.uri, { encoding: 'utf8' });
          const normalized = raw.replace(/\r\n/g, '\n').trim();
          if (!normalized) {
            unreadableNames.push(doc.name);
            continue;
          }
          const snippet = normalized.slice(0, maxCharsPerDoc);
          parsedSections.push(`[Document: ${doc.name}]\n${snippet}`);
          continue;
        } catch {
          // Fall through to backend extraction
        }
      }

      // Second try: send binary documents (PDF, DOCX, etc.) to backend for extraction
      try {
        const base64Data = await FileSystem.readAsStringAsync(doc.uri, { encoding: 'base64' });
        const dataUri = `data:${doc.mimeType || 'application/octet-stream'};base64,${base64Data}`;

        const { default: apiInstance } = await import('../services/api');
        const response = await apiInstance.post('extract-document-text/', {
          data: dataUri,
          filename: doc.name,
        });

        const extractedText = response.data?.text;
        if (extractedText && extractedText.trim()) {
          const snippet = extractedText.trim().slice(0, maxCharsPerDoc);
          parsedSections.push(`[Document: ${doc.name}]\n${snippet}`);
          continue;
        }

        // Backend returned empty text or error
        const backendError = response.data?.error;
        if (backendError) {
          console.warn(`Backend document extraction warning for ${doc.name}: ${backendError}`);
        }
        unreadableNames.push(doc.name);
      } catch (extractError) {
        console.warn(`Failed to extract document text for ${doc.name}:`, extractError);
        unreadableNames.push(doc.name);
      }
    }

    const context = parsedSections.length > 0
      ? `\n\nAttached document contents:\n\n${parsedSections.join('\n\n---\n\n')}`
      : '';

    return { context, unreadableNames };
  };

  const prepareImagePayloads = async (attachments: AttachmentItem[]): Promise<string[]> => {
    const imageAttachments = attachments.filter((item) => item.type === 'image');
    const payloads: string[] = [];

