      // 3rd choice: read from file system
      try {
        const base64 = await FileSystem.readAsStringAsync(attachment.uri, {
          encoding: 'base64',
        });
        const mimeType = attachment.mimeType || 'image/jpeg';
        payloads.push(`data:${mimeType};base64,${base64}`);
