      Animated.timing(keyboardAnim, {
        toValue: keyboardHeight,
        duration: event?.duration || 250,
        useNativeDriver: false,
      }).start();
      setTimeout(() => scrollViewRef.current?.scrollToEnd({ animated: true }), 100);
    });

    const hideSub = Keyboard.addListener('keyboardWillHide', (event: any) => {
      keyboardVisibleRef.current = false;
      Animated.timing(keyboardAnim, {
        toValue: 0,
        duration: event?.duration || 250,
        useNativeDriver: false,
      }).start();
    });

    return () => {
      showSub.remove();
      hideSub.remove();
    };
  }, [insets.bottom, keyboardAnim]);

  const fetchModels = async () => {
    try {
      const response = await chatService.getModels('chat');
      const chatModels = response.results || [];
      // Show all available chat models
      setModels(chatModels);
      if (chatModels.length > 0) {
        const restoredModel = restoredModelIdRef.current
          ? chatModels.find((m) => m.id === restoredModelIdRef.current)
          : null;
        setSelectedModel(restoredModel || chatModels[0]);
      }
    } catch (error) {
      Alert.alert(t('common.error'), t('chat.errorModels'));
    } finally {
      setIsLoading(false);
    }
  };

  // Load existing session if sessionId is provided
  useEffect(() => {
    if (initialSessionId) {
      loadExistingSession(initialSessionId);
    }
  }, [initialSessionId]);

