      // Format existing messages from session
      const existingMessages = sessionData.messages || [];
      const formattedMessages: Message[] = existingMessages.map((msg: any, index: number) => ({
        id: msg.id?.toString() || `msg-${index}`,
        content: msg.content || msg.message || '',
        isUser: msg.isUser ?? msg.is_user ?? (msg.role === 'user'),
        timestamp: msg.created_at || new Date().toISOString(),
        attachments: mapImagesToAttachments(msg.images || []),
      }));
      setMessages(formattedMessages);

      // Automatically connect to WebSocket for this session
      connectToExistingSession(sessionData);
    } catch (error) {
      console.error('Failed to load session:', error);
      Alert.alert(t('common.error'), t('chat.errorLoadSession'));
    } finally {
      setIsLoading(false);
    }
  };

  const connectToExistingSession = async (sessionData: ChatSession) => {
    if (isConnectingRef.current) return;

