  FORGOT_PASSWORD: '/accounts/forgot-password/',
  RESET_PASSWORD: '/accounts/reset-password/',
  PROFILE: '/accounts/profile/',
  TRANSACTIONS: '/accounts/transactions/',

  // AI Models
  MODELS_LIST: '/list/',

  // Chat Sessions
