  // Image Generation
  IMAGE_SESSIONS: '/chat/session/list/',
  IMAGE_TO_3D: '/image-to-3d/',
  IMAGE_UPSCALER: '/image-upscaler/',
  IMAGE_EDIT: '/image-edit/',

  // Plans
  PLANS: '/plan/list/',
  SUBSCRIBE: '/plan/subscribe/',

