const mockAsyncStorage = {
  getItem: jest.fn(),
};

const mockCreditsService = {
  getCreditBalance: jest.fn(),
};

jest.mock('@react-native-async-storage/async-storage', () => ({
  __esModule: true,
  default: {
    getItem: (...args: unknown[]) => mockAsyncStorage.getItem(...args),
  },
