            subject=subject,
            user_email=user_email,
            message=message,
            message_type=message_type,
        )
        return True
    except Exception:
        logger.exception("Failed to queue OTP email task; falling back to sync email")

    try:
        send_the_email(
            subject=subject,
            user_email=user_email,
            message=message,
            message_type=message_type,
        )
        return True
    except Exception:
        logger.exception("Fallback synchronous email also failed")
        return False


