def call_fal_ai(api_key, prompt,model,user_id,num_images=1,base_cost=None,seed=6252023, steps=50, cfg_scale=7.0, size="512x512", images_data_list=None):
    try:
        user = User.objects.get(id=user_id)
    except User.DoesNotExist:
        return {"error": "User Id not Found"}

    credit_account = CreditAccount.objects.filter(user=user).first()
    if not credit_account:
        credit_account = CreditAccount.objects.create(user=user, credits=0)


    image_deduct_credit = base_cost*num_images if base_cost else 500


    if credit_account.credits <image_deduct_credit:
        return {"error": "Insufficient credits! TOP UP NOW!"}

    credit_account.credits -= image_deduct_credit
    if credit_account.credits < 0:
        credit_account.credits = 0
    credit_account.save()
    trackUsedWords(user, word_count=image_deduct_credit)
    user.total_token_used+=image_deduct_credit
    user.save()


    try:
        # Set the API key dynamically for this session

        os.environ["FAL_KEY"] = api_key

        # Submit the request
        handler = fal_client.submit(
            model,
            arguments={
                "prompt": prompt,
                "seed": seed,
                "steps": steps,
                "cfg_scale": cfg_scale,
                "size": size
            }
        )

        result = handler.get()

        # Extract image URL
        images = result.get("images", [])
        # image_url = images[0].get("url") if images else None
        image_url = [img.get("url") for img in images if img]


        return {
            "text": "Image generated successfully.",
            "images": image_url
        }

    except Exception as e:
        credit_account.credits+=image_deduct_credit
        credit_account.save()
        user.total_token_used-=image_deduct_credit
        user.save()
        error_str = str(e)
        if "key" in error_str.lower():
            return {"error": "Authentication failed: Invalid API key."}
        return {"error": "Error generating image. Please try again later."}

from decimal import Decimal
import asyncio
import time
import requests
import base64
from django.contrib.auth import get_user_model
from django.db import transaction
from google import genai
from google.genai import types
from asgiref.sync import sync_to_async

from accounts.models import CreditAccount, CreditTransaction
from .track_used_word_subscription import trackUsedWords
from .image_to_url_save import download_and_store_webp

import math
User = get_user_model()

# =========================
# HELPER: Count Words (1 word = 5 non-space chars)
# =========================
def count_words(text):
    if not text:
        return 0
    # Remove spaces and calculate ceil(len/5)
    char_count = len(text.replace(" ", ""))
    return math.ceil(char_count / 5)
def calculate_cost(model_type, *, base_cost, words=0, num_images=1, input_images_count=0):
    base_cost = Decimal(str(base_cost))

    if model_type in {"chat", "text_generation", "code_generation", "image_understanding"}:
        return (Decimal(words) * base_cost) + (Decimal(input_images_count) * base_cost)

    if model_type == "image_generation" or model_type == "text_to_image":
        return Decimal(num_images) * base_cost

    return Decimal(base_cost)

# =========================
# HELPER: Detect Model Type
# =========================
def _detect_model_type(model_id):
    ml = model_id.lower()
    if any(x in ml for x in ["image", "img", "gen", "photo", "art", "text_to_image"]):
        return "text_to_image"
    return "chat"

# =========================
# HELPER: Error Response
# =========================
def _error(msg):
    return {"text": "", "images": [], "sender": "system", "error": msg}

# =========================
# HELPER: Read Image
# =========================
async def _read_image_to_base64_async(img):
    """Read an image URL or base64 data URI and return (raw_base64, mime_type)."""
    try:
        if img.startswith("data:"):
            # Extract mime type and raw base64 from data URI
            # Format: data:image/png;base64,iVBOR...
            header, encoded = img.split(",", 1) if "," in img else ("", img)
            mime = "image/png"
            if "image/jpeg" in header or "image/jpg" in header:
                mime = "image/jpeg"
            elif "image/webp" in header:
                mime = "image/webp"
            elif "image/gif" in header:
                mime = "image/gif"
            elif "image/png" in header:
                mime = "image/png"
            return encoded, mime
        elif img.startswith("http"):
            resp = await sync_to_async(requests.get)(img, timeout=30)
            resp.raise_for_status()
            content_type = resp.headers.get("Content-Type", "image/png").split(";")[0].strip()
            return base64.b64encode(resp.content).decode("utf-8"), content_type
        else:
            # Assume raw base64
            return img, "image/png"
    except Exception:
        return None, None

# =========================
# MAIN FUNCTION
# =========================
async def gemini_response(
    message,
    model_id,
    api_key,
    user_id,
    images_data_list=None,
    summary=None,
    num_images=1,
    base_cost=500,
    width=None,
    height=None,
    model_type=None,
    resolution="720p",
    detected_language="English"
):

    try:
        client = genai.Client(api_key=api_key)

        user = await sync_to_async(lambda: User.objects.filter(id=user_id).first())()
        if not user:
            return _error("User not found.")

        if not model_type:
            model_type = _detect_model_type(model_id)

        num_images = 1 # Force 1 image per request

        prompt_words = count_words(message)
        input_images_count = len(images_data_list) if images_data_list else 0

        charge_amount = calculate_cost(
            model_type,
            base_cost=base_cost,
            words=prompt_words,
            num_images=num_images,
            input_images_count=input_images_count
        )

        # Credit Deduction (Atomic)
        @sync_to_async
        def _deduct_credits_atomic():
            with transaction.atomic():
                acc = CreditAccount.objects.select_for_update().filter(user_id=user_id).first()
                if not acc: 
                    print(f"DEBUG: Credit account NOT FOUND for user_id {user_id}")
                    return None, 0

                print(f"DEBUG: Gemini Pre-deduction. User: {user_id}, Current: {acc.credits}, Charging: {charge_amount}")
                if acc.credits < charge_amount: 
                    return False, acc.credits

                acc.credits -= charge_amount
                acc.save(update_fields=["credits"])

                # Record transaction for usage stats
                CreditTransaction.objects.create(
                    credit_account=acc,
                    amount=int(charge_amount),
                    transaction_type='deduct',
                    message=f'Gemini {model_type} usage'
                )

                u = User.objects.get(id=user_id)
                u.total_token_used += charge_amount
                u.save(update_fields=["total_token_used"])

                # Only track words for character models
                if model_type in {"chat", "text_generation", "code_generation", "image_understanding"}:
                    trackUsedWords(user_id, prompt_words)

                print(f"DEBUG: Gemini Deduction SUCCESS. New Balance: {acc.credits}")
                return True, acc.credits

        success, current_credits = await _deduct_credits_atomic()
        if success is None: return _error("Credit account not found.")
        if success is False: return _error(f"Insufficient credits. Required: {charge_amount}")

        # Max Output Token Logic
        remaining_credits = current_credits
        if base_cost > 0:
            max_response_words = int(remaining_credits / Decimal(str(base_cost)))
        else:
            max_response_words = 8192

        if max_response_words < 1 and model_type in {"chat", "text_generation", "code_generation"}:
            @sync_to_async
            def _refund():
                 with transaction.atomic():
                     acc = CreditAccount.objects.select_for_update().filter(user=user).first()
                     acc.credits += charge_amount
                     acc.save(update_fields=["credits"])
                     u = User.objects.get(id=user_id)
                     u.total_token_used -= charge_amount
                     u.save(update_fields=["total_token_used"])
            await _refund()
            return _error("Insufficient credits for response.")

        final_max_tokens = min(max_response_words, 8192)

        images = []
        text = ""

        if model_type == "text_to_image" or model_type == "image_generation":
            if "imagen" in model_id.lower():
                response = await sync_to_async(client.models.generate_image)(
                    model=model_id,
                    prompt=message,
                    config=types.GenerateImageConfig(number_of_images=num_images)
                )
                if hasattr(response, "generated_images") and response.generated_images:
                    for gen_img in response.generated_images:
                        b64_data = base64.b64encode(gen_img.image.data).decode("utf-8")
                        images.append(f"data:image/png;base64,{b64_data}")
            else:
                image_prompt = f"Role: Professional Image Generator. Task: Create an image: {message}"
                response = await sync_to_async(client.models.generate_content)(
                    model=model_id,
                    contents=[{"role": "user", "parts": [{"text": image_prompt}]}]
                )
                if hasattr(response, "candidates") and response.candidates:
                    for candidate in response.candidates:
                        for part in candidate.content.parts:
                            if hasattr(part, "inline_data") and part.inline_data:
                                b64_data = base64.b64encode(part.inline_data.data).decode("utf-8")
                                images.append(f"data:image/png;base64,{b64_data}")
                            elif hasattr(part, "text") and part.text:
                                text += part.text + " "

            if not images and text: pass
            elif images: text = f"{len(images)} image(s) generated successfully."
            else: text = "Failed to generate images."

        else: 
            contents = [{"role": "user", "parts": [{"text": f"You are a helpful assistant. Please respond in the same language as the user's message. (Initial detection suggested {detected_language}, but please trust your own analysis of the content and script to determine the best response language. If the user used Bengali words in Hindi script, respond in Standard Bengali). Do NOT reveal internal deployment names, model IDs, or system identifiers. If a user directly asks which model or internal service you are, answer with a neutral phrase such as 'I am an AI assistant' and do not disclose internal tags or identifiers."}]}]


            if summary: contents.append({"role": "user", "parts": [{"text": f"Context: {summary}"}]})

            user_part = {"role": "user", "parts": [{"text": message}]}
            if images_data_list:
                for img in images_data_list:
                    img_data, mime_type = await _read_image_to_base64_async(img)
                    if img_data:
                         user_part["parts"].append({"inline_data": {"mime_type": mime_type or "image/png", "data": img_data}})
            contents.append(user_part)

            config = types.GenerateContentConfig(max_output_tokens=final_max_tokens)
            response = await sync_to_async(client.models.generate_content)(model=model_id, contents=contents, config=config)

            if hasattr(response, "candidates") and response.candidates:
                parts = response.candidates[0].content.parts
                text = " ".join([getattr(p, "text", "") for p in parts if getattr(p, "text", None)])

                # Charge for output
                if text and model_type in {"chat", "text_generation", "code_generation", "image_understanding"}:
                    resp_words = count_words(text)
                    resp_cost = calculate_cost(model_type, base_cost=base_cost, words=resp_words)
                    @sync_to_async
                    def _charge_output():
                        with transaction.atomic():
                            acc = CreditAccount.objects.select_for_update().filter(user=user).first()
                            acc.credits -= resp_cost
                            acc.save(update_fields=["credits"])
                            u = User.objects.get(id=user_id)
                            u.total_token_used += resp_cost
                            u.save(update_fields=["total_token_used"])
                    await _charge_output()

                # Check for inline images
                for part in parts:
                    if hasattr(part, "inline_data") and hasattr(part.inline_data, "data"):
                         b64_data = base64.b64encode(part.inline_data.data).decode("utf-8")
                         images.append(f"data:image/png;base64,{b64_data}")

        if images:
            images = await sync_to_async(download_and_store_webp)(images)

        return {"text": text, "images": images, "sender": "ai", "error": None}

    except Exception as e:
        error_str = str(e)
        print(f"ERROR in gemini_response: {error_str}")
        # Refund sync
        @sync_to_async
        def _final_refund():
            try:
                with transaction.atomic():
                    u = User.objects.filter(id=user_id).first()
                    acc = CreditAccount.objects.filter(user=u).first()
                    acc.credits += charge_amount
                    acc.save(update_fields=["credits"])
                    u.total_token_used -= charge_amount
                    u.save(update_fields=["total_token_used"])
            except: pass
        await _final_refund()

        # Provide specific error messages for known API errors
        if "429" in error_str or "RESOURCE_EXHAUSTED" in error_str:
            return _error("Gemini API quota exceeded. The API key has reached its rate limit. Please try again later or update the API key in the admin dashboard.")
        if "403" in error_str or "PERMISSION_DENIED" in error_str:
            return _error("Gemini API key is invalid or does not have permission. Please update the API key in the admin dashboard.")
        if "404" in error_str or "NOT_FOUND" in error_str:
            return _error(f"Model '{model_id}' not found. Please check the model ID in the admin dashboard.")

        return _error(f"AI request failed: {error_str[:200]}")

from openai import OpenAI
from django.contrib.auth import get_user_model
from accounts.models import CreditAccount, CreditTransaction
from django.db import transaction
from .track_used_word_subscription import trackUsedWords
from decimal import Decimal

import math

User = get_user_model()

GROQ_BASE_URL = "https://api.groq.com/openai/v1"


def count_words(text):
    if not text:
        return 0
    char_count = len(text.replace(" ", ""))
    return math.ceil(char_count / 5)


def _error(msg: str) -> dict:
    return {
        "text": "",
        "images": [],
        "sender": "system",
        "error": msg,
    }


def calculate_cost(base_cost, words):
    base_cost = Decimal(str(base_cost))
    return Decimal(words) * base_cost


def call_groq_for_chat(
    model_id: str,
    api_key: str,
    user_id: int,
    base_cost: int = 1,
    message: str = "",
    summary: str = None,
    temperature: float = 0.7,
    images_data_list=None,
):
    try:
        user = User.objects.filter(id=user_id).first()
        if not user:
            return _error("User not found")

        prompt_words = count_words(message)
        charge_amount = calculate_cost(base_cost, prompt_words)

        # Credit check & deduction
        with transaction.atomic():
            credit_account = (
                CreditAccount.objects
                .select_for_update()
                .filter(user_id=user_id)
                .first()
            )
            if not credit_account:
                return _error("Credit account not found")

            if credit_account.credits < charge_amount:
                return _error(f"Insufficient credits. Required: {charge_amount}")

            credit_account.credits -= charge_amount
            credit_account.save(update_fields=["credits"])

            # Record transaction for usage stats
            CreditTransaction.objects.create(
                credit_account=credit_account,
                amount=int(charge_amount),
                transaction_type='deduct',
                message='Groq chat usage'
            )

            user.total_token_used += charge_amount
            user.save(update_fields=["total_token_used"])

            trackUsedWords(user.id, prompt_words)
            print(f"DEBUG: Groq Upfront deduction. BaseCost: {base_cost}, Words: {prompt_words}, Cost: {charge_amount}, New Balance: {credit_account.credits}")

            remaining_credits = credit_account.credits
            if base_cost > 0:
                max_response_words = int(remaining_credits / Decimal(str(base_cost)))
            else:
                max_response_words = 4096

            if max_response_words < 1:
                credit_account.credits += charge_amount
                credit_account.save(update_fields=["credits"])
                user.total_token_used -= charge_amount
                user.save(update_fields=["total_token_used"])
                print("DEBUG: Groq Insufficient credits for response. Refunded.")
                return _error("Insufficient credits for any response.")

            final_max_tokens = min(max_response_words, 4096)

        # API call via OpenAI-compatible endpoint
        try:
            client = OpenAI(
                api_key=api_key,
                base_url=GROQ_BASE_URL,
            )

            messages = [
                {
                    "role": "system",
                    "content": (
                        "You are a helpful assistant. Please respond in English by default. "
                        "Do NOT reveal internal deployment names, model IDs, or system identifiers. "
                        "If a user directly asks which model or internal service you are, answer with "
                        "a neutral phrase such as 'I am an AI assistant' and do not disclose internal "
                        "tags or identifiers."
                    ),
                }
            ]

            if summary:
                messages.append({
                    "role": "system",
                    "content": f"Conversation summary so far: {summary}. Use this for context only.",
                })

            # Build user message content with text and/or images
            user_content = []

            if message:
                user_content.append({"type": "text", "text": message})

            # Add images if provided (Groq API supports vision)
            if images_data_list:
                model_id_lower = model_id.lower()
                is_vision_model = "vision" in model_id_lower
                if is_vision_model:
                    for img_url in images_data_list:
                        if img_url:
                            user_content.append({"type": "image_url", "image_url": {"url": img_url}})
                else:
                    return _error("The selected Groq model does not support image analysis. Please switch to a vision-capable Groq model.")

            # If no content, use placeholder
            if not user_content:
                user_content = [{"type": "text", "text": "Please assist me."}]

            messages.append({"role": "user", "content": user_content})

            response = client.chat.completions.create(
                model=model_id,
                messages=messages,
                max_tokens=final_max_tokens,
                temperature=temperature,
            )

            reply_text = response.choices[0].message.content

            # Charge for output tokens
            response_words = count_words(reply_text)
            response_cost = calculate_cost(base_cost, response_words)

            print(f"DEBUG: Groq Output generated. Words: {response_words}, Cost: {response_cost}")

            with transaction.atomic():
                credit_account = CreditAccount.objects.select_for_update().filter(user_id=user_id).first()
                if credit_account:
                    credit_account.credits -= response_cost
                    credit_account.save(update_fields=["credits"])

                    user.total_token_used += response_cost
                    user.save(update_fields=["total_token_used"])

                    trackUsedWords(user.id, response_words)
                    print(f"DEBUG: Groq Output deduction success. Final Balance: {credit_account.credits}")

            return {
                "text": reply_text,
                "images": [],
                "sender": "ai",
                "error": None,
            }

        except Exception as api_error:
            error_str = str(api_error)
            print(f"DEBUG: Groq API Error: {error_str}")
            with transaction.atomic():
                refund_account = CreditAccount.objects.select_for_update().filter(user_id=user_id).first()
                if refund_account:
                    refund_account.credits += charge_amount
                    refund_account.save(update_fields=["credits"])

                    user.total_token_used -= charge_amount
                    user.save(update_fields=["total_token_used"])
                    print(f"DEBUG: Groq Refunded {charge_amount} credits.")

            if "api_key" in error_str.lower() or "api key" in error_str.lower():
                return _error("Authentication failed: Invalid API key or configuration.")
            if "rate_limit" in error_str.lower() or "429" in error_str:
                return _error("Groq rate limit exceeded. Please try again in a moment.")

            return _error(f"API error. Please try again later.")

    except Exception as e:
        print(f"DEBUG: Groq system error: {e}")
        return _error("System error occurred.")

import requests
from accounts.models import CreditAccount, User
from .track_used_word_subscription import trackUsedWords
from .image_to_url_save import download_and_store_webp  # your existing function
import math

# Helper: Count Words (1 word = 5 non-space chars)
def count_words(text):
    if not text:
        return 0
    char_count = len(text.replace(" ", ""))
    return math.ceil(char_count / 5)

# Cache for model_id → allowed_resolutions
MODEL_INFO_CACHE = {}

def refresh_model_info(api_key):
    """
    Fetches Leonardo models and caches allowed resolutions for each model_id.
    """
    url = "https://cloud.leonardo.ai/api/rest/v1/models"
    headers = {"Authorization": f"Bearer {api_key}"}
    resp = requests.get(url, headers=headers, timeout=30)
    resp.raise_for_status()
    models = resp.json().get("models", [])
    for m in models:
        model_id = m["id"]
        allowed = m.get("allowed_resolutions") or [256, 512, 768, 1024]
        MODEL_INFO_CACHE[model_id] = allowed

def leonardo_response(
    prompt: str,
    user_id: int,
    model_id: str,
    num_images: int = 1,
    width: int = 512,
    height: int = 512,
    api_key: str = None,
    BASE_COST: int = 500,
    max_images_per_request: int = 1,
    images_data_list=None,
    summary: str = None,
):
    try:

        # -------------------------
        user = User.objects.filter(id=user_id).first()
        if not user:
            return {"images": [], "error": "User not found.", "sender": "system"}

        credit_account = CreditAccount.objects.filter(user=user).first()
        if not credit_account:

            # return {"images": [], "error": "Credit account not found.", "sender": "system"}
            credit_account=CreditAccount.objects.create(user=user,credits=0)

        if not api_key:
            return {"images": [], "error": "API key missing.", "sender": "system"}


        if model_id not in MODEL_INFO_CACHE:
            refresh_model_info(api_key)

        allowed_sizes = MODEL_INFO_CACHE.get(model_id)
        if not allowed_sizes:
            return {"images": [], "error": f"Unknown model {model_id}", "sender": "system"}


        if width not in allowed_sizes or height not in allowed_sizes:
            width = max([s for s in allowed_sizes if s <= width], default=min(allowed_sizes))
            height = max([s for s in allowed_sizes if s <= height], default=min(allowed_sizes))

        num_images = min(num_images, max_images_per_request)


        # resolution_factor = (width * height) / (512 * 512)

        image_cost = int(BASE_COST)
        total_cost = image_cost * num_images

        if credit_account.credits < total_cost:
            return {"images": [], "error": "Not enough credits for requested image(s).", "sender": "system"}


        credit_account.credits -= total_cost
        if credit_account.credits < 0:
            credit_account.credits = 0
        credit_account.save()
        # Non-char models (image) don't track prompt words cost/usage
        user.total_token_used += total_cost # Track by cost instead
        user.save()

        payload = {
            "prompt": prompt,
            "num_images": num_images,
            "width": width,
            "height": height,
            "modelId": model_id
        }
        headers = {"Authorization": f"Bearer {api_key}", "Content-Type": "application/json"}
        response = requests.post("https://cloud.leonardo.ai/api/rest/v1/generations", json=payload, headers=headers, timeout=60)

        if response.status_code != 200:
            # Refund credits if API fails
            credit_account.credits += total_cost
            credit_account.save()
            return {"images": [], "error": f"Leonardo API error: {response.status_code} {response.text}", "sender": "system"}
        else:
            trackUsedWords(user.id, total_cost)

        data = response.json()
        temp_urls = []
        for img_block in data.get("sdGenerationJob", {}).get("generated_images", []):
            url = img_block.get("url")
            if url:
                temp_urls.append(url)


        permanent_urls = download_and_store_webp(temp_urls)

        return {"images": permanent_urls, "error": None, "sender": "ai"}

    except Exception as e:
        if 'credit_account' in locals():
            credit_account.credits += total_cost
