from rest_framework import serializers
from .models import AIModelInfo, ChatMessage, ChatSession


class AIModelSerializer(serializers.ModelSerializer):
    """
    Full serializer for AI models (admin use).
    Includes all fields including sensitive API keys.
    """
    class Meta:
        model = AIModelInfo
        fields = '__all__'
        read_only_fields = ['created_at', 'updated_at']

    def validate(self, attrs):
        """Validate that image generating models have a base cost."""
        images_generating_models = attrs.get('images_generating_models', False)
        base_cost = attrs.get('base_cost', None)

        if images_generating_models and (base_cost is None or base_cost <= 0):
            raise serializers.ValidationError(
                {"base_cost": "Base cost must be greater than 0 for image generating models."}
            )
        return attrs


class AIModelLimitedSerializer(serializers.ModelSerializer):
    """Limited serializer for AI models (authenticated users)."""
    class Meta:
        model = AIModelInfo
        fields = ['id', 'name', 'image', 'logo', 'model_id', 'created_at', 'description', 'base_url', 'base_cost', 'model_type', 'provider']
        read_only_fields = ['created_at', 'updated_at']


class AIModelPublicSerializer(serializers.ModelSerializer):
    """Public serializer for AI models without sensitive data like API keys."""
    class Meta:
        model = AIModelInfo
        fields = ['id', 'name', 'image', 'logo', 'model_id', 'description', 'provider', 'model_type', 'base_cost']
        read_only_fields = fields


class ChatMessageSerializer(serializers.ModelSerializer):
    """Serializer for individual chat messages."""
    class Meta:
        model = ChatMessage
        fields = "__all__"


class ChatSessionSerializer(serializers.ModelSerializer):
    """
    Serializer for chat sessions.

    Includes nested messages and validates model/session type compatibility.
    """
    messages = ChatMessageSerializer(read_only=True, many=True)

    model = serializers.PrimaryKeyRelatedField(
        queryset=AIModelInfo.objects.all()
    )
    model_name = serializers.SerializerMethodField(read_only=True)

    class Meta:
        model = ChatSession
        fields = [
            'id',
            'model',
            'model_name',
            'user',
            'messages',
            'summary',
            'session_type',
            'created_at',
            'updated_at',
        ]
        read_only_fields = [
            'id',
            'created_at',
            'updated_at',
            'user',
            'messages',
            'model_name'
        ]

    def validate(self, attrs):
        model = attrs.get('model')          # AIModelInfo instance
        session_type = attrs.get('session_type')

        if not model:
            raise serializers.ValidationError(
                {"model": "Model is required."}
            )

        if not session_type:
            raise serializers.ValidationError(
                {"session_type": "Session type is required."}
            )

        if not self._is_compatible(model.model_type, session_type):
            raise serializers.ValidationError(
                {"error": "Model type and session type must be compatible."}
            )

        return attrs

    def _is_compatible(self, model_type, session_type):
        if model_type == session_type:
            return True

        if model_type == "text_or_image_to_video":
            return session_type in [
                "text_to_video",
                "image_to_video",
                "text_or_image_to_video",
            ]

        return False
    def get_model_name(self, obj):
        return obj.model.name if obj.model else None

import requests
import json
import asyncio
import time
from django.contrib.auth import get_user_model
from accounts.models import CreditAccount
from .track_used_word_subscription import trackUsedWords
from asgiref.sync import sync_to_async
from django.db import transaction
from decimal import Decimal

User = get_user_model()

async def wavespeed_ai_call(model_id, api_key, payload=None, poll_interval=0.5, user_id=None, base_cost=500):
    if payload is None:
        payload = {
            "prompt": "A futuristic city skyline at sunset",
            "strength": 0.8,
            "size": "1024*1024",
            "num_inference_steps": 28,
            "seed": -1,
            "guidance_scale": 3.5,
            "num_images": 1,
            "output_format": "jpeg",
            "enable_base64_output": False,
            "enable_sync_mode": False
        }

    try:
        user = await sync_to_async(User.objects.get)(id=user_id)
    except User.DoesNotExist:
        return {"error": "User Id not Found"}

    print("payload:", payload)
    credit_account = await sync_to_async(lambda: CreditAccount.objects.filter(user=user).first())()
    if not credit_account:
        credit_account = await sync_to_async(CreditAccount.objects.create)(user=user, credits=0)

    num_images = payload.get('num_images', 1)
    image_deduct_credit = base_cost * num_images

    if credit_account.credits < image_deduct_credit:
        return {"error": "Insufficient credits! TOP UP NOW!"}

    headers = {
        "Content-Type": "application/json",
        "Authorization": f"Bearer {api_key}"
    }

    url = f"https://api.wavespeed.ai/api/v3/{model_id}"

    try:
        # Run synchronous requests in a thread pool using sync_to_async
        response = await sync_to_async(requests.post, thread_sensitive=False)(url, headers=headers, data=json.dumps(payload), timeout=60)
        response.raise_for_status()
    except requests.exceptions.HTTPError as e:
        error_detail = ""
        try:
            error_detail = e.response.json().get("message", str(e))
        except:
            error_detail = str(e)
        print(f"WaveSpeedAI HTTP Error: {error_detail}")
        if "api_key" in error_detail.lower() or "authorization" in error_detail.lower():
            return {"error": "Authentication failed: Invalid API key."}
        if "insufficient" in error_detail.lower() or "credit" in error_detail.lower():
            return {"error": "WaveSpeedAI service unavailable. The API provider needs to top up their credits. Please try a different model or contact support."}
        return {"error": f"WaveSpeedAI Error: {error_detail}"}
    except Exception as e:
        error_str = str(e)
        print(f"WaveSpeedAI Request Error: {error_str}")
        if "api_key" in error_str.lower() or "authorization" in error_str.lower():
            return {"error": "Authentication failed: Invalid API key."}
        return {"error": f"Request error: {error_str}"}

    request_id = response.json().get("data", {}).get("id")
    if not request_id:
        return {"error": "No request ID returned"}

    result_url = f"https://api.wavespeed.ai/api/v3/predictions/{request_id}/result"
    start_time = time.time()

    status = "pending"
    result = {}

    while True:
        try:
            # Check for total timeout (10 minutes)
            if time.time() - start_time > 600:
                return {"error": "Request timed out after 10 minutes"}

            resp = await sync_to_async(requests.get, thread_sensitive=False)(result_url, headers={"Authorization": f"Bearer {api_key}"}, timeout=20)
            resp.raise_for_status()
        except Exception as e:
            return {"error": f"Error checking status: {str(e)}"}

        result = resp.json().get("data", {})
        status = result.get("status")

        if status not in ["completed", "failed"]:
            await asyncio.sleep(poll_interval)
        else:
            break

    if status == "completed":
        print(f"Task completed.")

        # Deduct credits atomically in a separate sync function
        def _process_credits():
            with transaction.atomic():
                ca = CreditAccount.objects.select_for_update().filter(user_id=user_id).first()
                if not ca:
                    print(f"DEBUG: Wavespeed Credit account NOT FOUND for user_id {user_id}")
                    return
                print(f"DEBUG: Wavespeed Pre-deduction. User: {user_id}, Current: {ca.credits}, Charging: {image_deduct_credit}")
                ca.credits -= Decimal(str(image_deduct_credit))
                if ca.credits < 0:
                    ca.credits = 0
                ca.save(update_fields=["credits"])

                u = User.objects.get(id=user_id)
                u.total_token_used += Decimal(str(image_deduct_credit))
                u.save(update_fields=["total_token_used"])
                print(f"DEBUG: Wavespeed Deduction SUCCESS. New Balance: {ca.credits}")

        await sync_to_async(_process_credits)()
        # Image models don't track words

        output_url = result.get("outputs", [None])[0]
        elapsed = time.time() - start_time
        return {
            "text": f"Image generated successfully ({payload.get('size')}) in {elapsed:.2f} seconds.",
            "images": [output_url] if output_url else []
        }

    elif status == "failed":
        print("Generation failed")
        return {"error": result.get("error", "Generation failed")}

    return {"error": "Unknown status"}

import json
import hmac
import hashlib
import logging
from django.http import JsonResponse
from django.views.decorators.csrf import csrf_exempt
from django.conf import settings

logger = logging.getLogger(__name__)


def _is_valid_signature(raw_body, signature_header):
    """Validate webhook signature using HMAC-SHA256 and a shared secret."""
    secret = getattr(settings, "AI_WEBHOOK_SECRET", "")
    if not secret or not signature_header:
        return False

    expected = hmac.new(
        secret.encode("utf-8"),
        raw_body,
        hashlib.sha256,
    ).hexdigest()
    provided = signature_header.strip()
    if provided.startswith("sha256="):
        provided = provided.split("=", 1)[1]
    return hmac.compare_digest(expected, provided)

@csrf_exempt
def video_webhook(request):
    if request.method != "POST":
        return JsonResponse({"status": "method not allowed"}, status=405)

    signature = request.headers.get("X-Webhook-Signature", "")
    if not _is_valid_signature(request.body, signature):
        logger.warning("Webhook rejected due to invalid or missing signature")
        return JsonResponse({"status": "invalid signature"}, status=401)

    try:
        event = json.loads(request.body)
        event_type = event.get("type")
        data = event.get("data", {})

        if event_type == "video.completed":
            video_id = data.get("id")
            logger.info("Video completed webhook received for id=%s", video_id)
            # TODO: Fetch video content using video_id if needed
        elif event_type == "video.failed":
            logger.warning("Video failed webhook received")

        return JsonResponse({"status": "received"})
    except Exception:
        logger.exception("Webhook processing error")
        return JsonResponse({"status": "error"}, status=400)

